Value.Calculation:
Let([
	ts = GetAsTimestamp ( Get ( CurrentHostTimestamp ) ) ;
	d = GetAsDate ( ts ) ;
	t = GetAsTime ( ts )
] ;
	Year ( d ) & "-" & Right ( "0" & Month ( d ) ; 2 ) & "-" & Right ( "0" & Day ( d ) ; 2 ) & "T" &
	Right ( "0" & Hour ( t ) ; 2 ) & ":" & Right ( "0" & Minute ( t ) ; 2 ) & ":" & Right ( "0" & Int ( Seconds ( t ) ) ; 2 ) & "Z"
)

Case (
	GetAsNumber ( $$SYNC_VO_PUSH_ALL ) = 1 ; 1 ;
	Lower ( TrimAll ( GetAsText ( $$SYNC_VO_PUSH_ALL ) ; 1 ; 1 ) ) = "x" ; 1 ;
	Lower ( TrimAll ( GetAsText ( $$SYNC_VO_PUSH_ALL ) ; 1 ; 1 ) ) = "true" ; 1 ;
	0
)

Let([
	own_sql = Case (
		IsEmpty ( $mk_raw ) ; "" ;
		Filter ( $mk_raw ; "0123456789" ) = $mk_raw ;
		MBS("FM.SQL.Execute"; "";
		"SELECT \"Vertragseigentümer\" as \"owner\" FROM \"" & $$FM_VERTRAEGE_TABELLE & "\" WHERE \"Vertrag_ID\" = " & GetAsNumber ( $mk_raw )
		) ;
		MBS("FM.SQL.Execute"; "";
		"SELECT \"Vertragseigentümer\" as \"owner\" FROM \"" & $$FM_VERTRAEGE_TABELLE & "\" WHERE \"Vertrag_ID\" = '" & Substitute ( $mk_raw ; "'" ; "''" ) & "'"
		)
	) ;
	own_val = Case (
		Left ( own_sql ; 5 ) = "[MBS]" or IsEmpty ( own_sql ) ; "" ;
		Lower ( Substitute ( TrimAll ( GetAsText ( MBS("FM.SQL.Field"; own_sql; 0; 0 ) ) ; 1 ; 1 ) ; "+" ; "-" ; " " ; "-" ; "&" ; "-" ; "/" ; "-" ; "_" ; "-" ) )
	) ;
	own_rel = Case ( Left ( own_sql ; 5 ) = "[MBS]" or IsEmpty ( own_sql ) ; "" ; MBS("FM.SQL.Release"; own_sql) )
] ;
	own_val

Case (
	$push_all = 1 ;
	MBS("FM.SQL.Execute"; "";
	"SELECT \"Vorgang_ID\", \"Vertrag\", \"Vorgang_Art\", \"Art der Erledigung\", \"Beschreibung\", \"Datum\", \"Frist\", \"Datei\", \"Erledigung\", \"Nachfrist\", \"Erledigt\", \"Ersteller\", \"Verantwortlicher\", \"SB\", \"BVH\", \"BA\", \"GEW\", \"AN\", \"A_NR\", \"Kunde\", \"WE\", \"Grundstück\", \"Makler\", \"Interessent\" FROM \"" & $$FM_VORGAENGE_TABELLE & "\"") ;
	IsEmpty ( TrimAll ( $marked_sql_list ; 1 ; 1 ) ) ;
	MBS("FM.SQL.Execute"; "";
	"SELECT \"Vorgang_ID\", \"Vertrag\", \"Vorgang_Art\", \"Art der Erledigung\", \"Beschreibung\", \"Datum\", \"Frist\", \"Datei\", \"Erledigung\", \"Nachfrist\", \"Erledigt\", \"Ersteller\", \"Verantwortlicher\", \"SB\", \"BVH\", \"BA\", \"GEW\", \"AN\", \"A_NR\", \"Kunde\", \"WE\", \"Grundstück\", \"Makler\", \"Interessent\" FROM \"" & $$FM_VORGAENGE_TABELLE & "\" WHERE 1=0") ;
	MBS("FM.SQL.Execute"; "";
	"SELECT \"Vorgang_ID\", \"Vertrag\", \"Vorgang_Art\", \"Art der Erledigung\", \"Beschreibung\", \"Datum\", \"Frist\", \"Datei\", \"Erledigung\", \"Nachfrist\", \"Erledigt\", \"Ersteller\", \"Verantwortlicher\", \"SB\", \"BVH\", \"BA\", \"GEW\", \"AN\", \"A_NR\", \"Kunde\", \"WE\", \"Grundstück\", \"Makler\", \"Interessent\" FROM \"" & $$FM_VORGAENGE_TABELLE & "\" WHERE \"Vertrag\" IN (" & Substitute ( $marked_sql_list ; ¶ ; "," ) & ")")
)

Let([
	v0_raw = TrimAll ( GetAsText ( MBS("FM.SQL.Field"; $sql; 0; 1 ) ) ; 1 ; 1 ) ;
	v0_low = Lower ( v0_raw ) ;
	test_sql = Case (
		IsEmpty ( v0_raw ) ; "" ;
		Filter ( v0_raw ; "0123456789" ) = v0_raw ;
		MBS("FM.SQL.Execute"; "";
		"SELECT \"Vertragseigentümer\" as \"owner\" FROM \"" & $$FM_VERTRAEGE_TABELLE & "\" WHERE \"Vertrag_ID\" = " & GetAsNumber ( v0_raw )
		) ;
		MBS("FM.SQL.Execute"; "";
		"SELECT \"Vertragseigentümer\" as \"owner\" FROM \"" & $$FM_VERTRAEGE_TABELLE & "\" WHERE \"Vertrag_ID\" = '" & Substitute ( v0_raw ; "'" ; "''" ) & "'"
		)
	) ;
	test_owner = Case ( Left ( test_sql ; 5 ) = "[MBS]" ; "SQL_ERR: " & Left ( test_sql ; 80 ) ; IsEmpty ( test_sql ) ; "(leer)" ; Lower ( TrimAll ( GetAsText ( MBS("FM.SQL.Field"; test_sql; 0; 0 ) ) ; 1 ; 1 ) ) ) ;
	test_sql2 = Case (
		IsEmpty ( v0_raw ) ; "" ;
		MBS("FM.SQL.Execute"; "";
		"SELECT \"Vertrag_ID\" as \"vertrag_id\", \"Vertragseigentümer\" as \"owner\" FROM \"" & $$FM_VERTRAEGE_TABELLE & "\" WHERE \"Archivy_sync\" IN ('x','X')"
		)
	) ;
	row0_id = Case ( Left ( test_sql2 ; 5 ) = "[MBS]" ; "ERR" ; TrimAll ( GetAsText ( MBS("FM.SQL.Field"; test_sql2; 0; 0 ) ) ; 1 ; 1 ) ) ;
	row0_own = Case ( Left ( test_sql2 ; 5 ) = "[MBS]" ; "ERR" ; TrimAll ( GetAsText ( MBS("FM.SQL.Field"; test_sql2; 0; 1 ) ) ; 1 ; 1 ) ) ;
	ignore1 = Case ( Left ( test_sql ; 5 ) <> "[MBS]" and not IsEmpty ( test_sql ) ; MBS("FM.SQL.Release"; test_sql) ; "" ) ;
	ignore2 = Case ( Left ( test_sql2 ; 5 ) <> "[MBS]" and not IsEmpty ( test_sql2 ) ; MBS("FM.SQL.Release"; test_sql2) ; "" )
] ;
"PRECHECK:" &
" marked_count=" & $marked_count &
" | marked_sql_list=" & Left ( Substitute ( $marked_sql_list ; ¶ ; "," ) ; 100 ) &
" | marked_diag=" & Left ( Substitute ( $marked_diag ; ¶ ; " / " ) ; 120 ) &
" | owner_map=" & Left ( Substitute ( $owner_map ; ¶ ; " / " ) ; 200 ) &
" | anzahl_vorgaenge=" & $anzahl &
" | vo0_vertrag_raw=[" & v0_raw & "]" &
" | vo0_vertrag_lower=[" & v0_low & "]" &
" | owner_lookup_test=[" & test_owner & "]" &
" | vt0_id=[" & row0_id & "] vt0_owner=[" & row0_own & "]"
)

JSONSetElement ( "{}" ;
[ "vorgang_id" ; $vorgang_id_trim ; JSONString ] ;
[ "vertrag" ; MBS("FM.SQL.Field"; $sql; $idx; 1 ) ; JSONString ] ;
[ "vorgang_art" ; MBS("FM.SQL.Field"; $sql; $idx; 2 ) ; JSONString ] ;
[ "art_der_erledigung" ; MBS("FM.SQL.Field"; $sql; $idx; 3 ) ; JSONString ] ;
[ "beschreibung" ; MBS("FM.SQL.Field"; $sql; $idx; 4 ) ; JSONString ] ;
[ "datum" ; MBS("FM.SQL.Field"; $sql; $idx; 5 ) ; JSONString ] ;
[ "frist" ; MBS("FM.SQL.Field"; $sql; $idx; 6 ) ; JSONString ] ;
[ "datei" ; MBS("FM.SQL.Field"; $sql; $idx; 7 ) ; JSONString ] ;
[ "erledigung" ; MBS("FM.SQL.Field"; $sql; $idx; 8 ) ; JSONString ] ;
[ "nachfrist" ; MBS("FM.SQL.Field"; $sql; $idx; 9 ) ; JSONString ] ;
[ "erledigt" ; MBS("FM.SQL.Field"; $sql; $idx; 10 ) ; JSONString ] ;
[ "ersteller" ; MBS("FM.SQL.Field"; $sql; $idx; 11 ) ; JSONString ] ;
[ "verantwortlicher" ; MBS("FM.SQL.Field"; $sql; $idx; 12 ) ; JSONString ] ;
[ "sb" ; MBS("FM.SQL.Field"; $sql; $idx; 13 ) ; JSONString ]
)

Case (
	IsEmpty ( $vertrag_raw ) ; "" ;
	Filter ( $vertrag_raw ; "0123456789" ) = $vertrag_raw ;
	MBS("FM.SQL.Execute"; "";
	"SELECT \"Vertragseigentümer\" as \"owner\" FROM \"" & $$FM_VERTRAEGE_TABELLE & "\" WHERE \"Vertrag_ID\" = " & GetAsNumber ( $vertrag_raw )
	) ;
	MBS("FM.SQL.Execute"; "";
	"SELECT \"Vertragseigentümer\" as \"owner\" FROM \"" & $$FM_VERTRAEGE_TABELLE & "\" WHERE \"Vertrag_ID\" = '" & Substitute ( $vertrag_raw ; "'" ; "''" ) & "'"
	)
)

Let([
	v_raw = $vertrag_raw ;
	v_sql = Case (
		IsEmpty ( v_raw ) ; "" ;
		Filter ( v_raw ; "0123456789" ) = v_raw ;
		MBS("FM.SQL.Execute"; "";
		"SELECT \"Vertragseigentümer\" as \"owner\" FROM \"" & $$FM_VERTRAEGE_TABELLE & "\" WHERE \"Vertrag_ID\" = " & GetAsNumber ( v_raw )
		) ;
		MBS("FM.SQL.Execute"; "";
		"SELECT \"Vertragseigentümer\" as \"owner\" FROM \"" & $$FM_VERTRAEGE_TABELLE & "\" WHERE \"Vertrag_ID\" = '" & Substitute ( v_raw ; "'" ; "''" ) & "'"
		)
	) ;
	v_owner = Case ( Left ( v_sql ; 5 ) = "[MBS]" or IsEmpty ( v_sql ) ; "" ; Lower ( Substitute ( TrimAll ( GetAsText ( MBS("FM.SQL.Field"; v_sql; 0; 0 ) ) ; 1 ; 1 ) ; "+" ; "-" ; " " ; "-" ; "&" ; "-" ; "/" ; "-" ; "_" ; "-" ) ) ) ;
	v_rel = Case ( Left ( v_sql ; 5 ) = "[MBS]" or IsEmpty ( v_sql ) ; "" ; MBS("FM.SQL.Release"; v_sql) )
] ;
	Case ( not IsEmpty ( v_owner ) ; v_owner ; $owner_from_map )
)

Let([
	dat_trim = TrimAll ( GetAsText ( JSONGetElement ( $row_json ; "datum" ) ) ; 1 ; 1 ) ;
	frist_trim = TrimAll ( GetAsText ( JSONGetElement ( $row_json ; "frist" ) ) ; 1 ; 1 ) ;
	kurz_trim = TrimAll ( GetAsText ( JSONGetElement ( $row_json ; "art_der_erledigung" ) ) ; 1 ; 1 ) ;
	besch_trim = TrimAll ( GetAsText ( MBS("FM.SQL.Field"; $sql; $idx; 4 ) ) ; 1 ; 1 ) ;
	erl_trim = TrimAll ( GetAsText ( JSONGetElement ( $row_json ; "erledigung" ) ) ; 1 ; 1 ) ;
	nach_trim = TrimAll ( GetAsText ( JSONGetElement ( $row_json ; "nachfrist" ) ) ; 1 ; 1 ) ;
	datei_trim = TrimAll ( GetAsText ( JSONGetElement ( $row_json ; "datei" ) ) ; 1 ; 1 )
];
JSONSetElement ( "{}" ;
[ "vorgang_id" ; JSONGetElement ( $row_json ; "vorgang_id" ) ; JSONString ] ;
[ "vertragsbesitzer_id" ; Let([
		v_raw = $vertrag_raw ;
		v_sql = Case (
			IsEmpty ( v_raw ) ; "" ;
			Filter ( v_raw ; "0123456789" ) = v_raw ;
			MBS("FM.SQL.Execute"; "";
			"SELECT \"Vertragseigentümer\" as \"owner\" FROM \"" & $$FM_VERTRAEGE_TABELLE & "\" WHERE \"Vertrag_ID\" = " & GetAsNumber ( v_raw )
			) ;
			MBS("FM.SQL.Execute"; "";
			"SELECT \"Vertragseigentümer\" as \"owner\" FROM \"" & $$FM_VERTRAEGE_TABELLE & "\" WHERE \"Vertrag_ID\" = '" & Substitute ( v_raw ; "'" ; "''" ) & "'"
			)
		) ;
		v_owner = Case ( Left ( v_sql ; 5 ) = "[MBS]" or IsEmpty ( v_sql ) ; "" ; Lower ( Substitute ( TrimAll ( GetAsText ( MBS("FM.SQL.Field"; v_sql; 0; 0 ) ) ; 1 ; 1 ) ; "+" ; "-" ; " " ; "-" ; "&" ; "-" ; "/" ; "-" ; "_" ; "-" ) ) )
	] ; v_owner ) ; JSONString ] ;
[ "vorgang_art" ; JSONGetElement ( $row_json ; "vorgang_art" ) ; JSONString ] ;
[ "kurzbeschreibung" ; kurz_trim ; JSONString ] ;
[ "beschreibung" ; besch_trim ; JSONString ] ;
[ "datum" ; dat_trim ; JSONString ] ;
[ "frist" ; frist_trim ; JSONString ] ;
[ "erledigung" ; erl_trim ; JSONString ] ;
[ "nachfrist" ; nach_trim ; JSONString ] ;
[ "datei_pfad" ; datei_trim ; JSONString ] ;
[ "erledigt" ; Case ( not IsEmpty ( erl_trim ) and GetAsDate ( erl_trim ) <= GetAsDate ( Get ( CurrentDate ) ) ; 1 ; 0 ) ; JSONBoolean ] ;
[ "ersteller" ; JSONGetElement ( $row_json ; "ersteller" ) ; JSONString ] ;
[ "verantwortlicher" ; JSONGetElement ( $row_json ; "verantwortlicher" ) ; JSONString ] ;
[ "sb" ; JSONGetElement ( $row_json ; "sb" ) ; JSONString ] ;
[ "app_modified_at" ; $ts_iso ; JSONString ] ;
[ "sync_state" ; "geaendert" ; JSONString ]
)

JSONSetElement ( "{}" ;
[ "vorgang_id" ; TrimAll ( GetAsText ( MBS("FM.SQL.Field"; $sql; $idx; 0 ) ) ; 1 ; 1 ) ; JSONString ] ;
[ "vertragsbesitzer_id" ; Let([
		v_raw = $vertrag_raw ;
		v_sql = Case (
			IsEmpty ( v_raw ) ; "" ;
			Filter ( v_raw ; "0123456789" ) = v_raw ;
			MBS("FM.SQL.Execute"; "";
			"SELECT \"Vertragseigentümer\" as \"owner\" FROM \"" & $$FM_VERTRAEGE_TABELLE & "\" WHERE \"Vertrag_ID\" = " & GetAsNumber ( v_raw )
			) ;
			MBS("FM.SQL.Execute"; "";
			"SELECT \"Vertragseigentümer\" as \"owner\" FROM \"" & $$FM_VERTRAEGE_TABELLE & "\" WHERE \"Vertrag_ID\" = '" & Substitute ( v_raw ; "'" ; "''" ) & "'"
			)
		) ;
		v_owner = Case ( Left ( v_sql ; 5 ) = "[MBS]" or IsEmpty ( v_sql ) ; "" ; Lower ( Substitute ( TrimAll ( GetAsText ( MBS("FM.SQL.Field"; v_sql; 0; 0 ) ) ; 1 ; 1 ) ; "+" ; "-" ; " " ; "-" ; "&" ; "-" ; "/" ; "-" ; "_" ; "-" ) ) )
	] ; v_owner ) ; JSONString ] ;
[ "beschreibung" ; TrimAll ( GetAsText ( MBS("FM.SQL.Field"; $sql; $idx; 4 ) ) ; 1 ; 1 ) ; JSONString ] ;
[ "app_modified_at" ; $ts_iso ; JSONString ] ;
[ "sync_state" ; "geaendert" ; JSONString ]
)
